const deliveryListAttemptsByGrant = `-- name: DeliveryListAttemptsByGrant :many
SELECT id, grant_id, order_id, store_id, channel, result, safe_error_code, retry_count,
       actor_user_id, actor_kind, reason, idempotency_key, created_at
FROM delivery_attempts
WHERE grant_id = $1
ORDER BY created_at DESC, id DESC
LIMIT $2
`

type DeliveryListAttemptsByGrantParams struct {
	GrantID string `json:"grant_id"`
	Limit   int32  `json:"limit"`
}

func (q *Queries) DeliveryListAttemptsByGrant(ctx context.Context, arg DeliveryListAttemptsByGrantParams) ([]DeliveryAttempt, error) {
	rows, err := q.db.Query(ctx, deliveryListAttemptsByGrant, arg.GrantID, arg.Limit)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	items := []DeliveryAttempt{}
	for rows.Next() {
		var i DeliveryAttempt
		if err := rows.Scan(
			&i.ID,
			&i.GrantID,
			&i.OrderID,
			&i.StoreID,
			&i.Channel,
			&i.Result,
			&i.SafeErrorCode,
			&i.RetryCount,
			&i.ActorUserID,
			&i.ActorKind,
			&i.Reason,
			&i.IdempotencyKey,
			&i.CreatedAt,
		); err != nil {
			return nil, err
		}
		items = append(items, i)
	}
	if err := rows.Err(); err != nil {
		return nil, err
	}
	return items, nil
}

