const deliveryUserIsPlatformAdmin = `-- name: DeliveryUserIsPlatformAdmin :one
SELECT EXISTS (
    SELECT 1
    FROM user_roles ur
    JOIN roles r ON r.id = ur.role_id
    WHERE ur.user_id = $1
      AND r.archived_at IS NULL
      AND r.code IN ('SUPER_ADMIN', 'ADMIN_SUPPORT')
) AS ok
`

func (q *Queries) DeliveryUserIsPlatformAdmin(ctx context.Context, userID string) (bool, error) {
	row := q.db.QueryRow(ctx, deliveryUserIsPlatformAdmin, userID)
	var ok bool
	err := row.Scan(&ok)
	return ok, err
}
